INSERT INTO `properties` VALUES (1,2,'9500 Wawona Court','Luxury Mountain Experience','<p class=\"p1\" style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-stretch: normal; font-size: 13px; line-height: normal; font-family: &quot;Helvetica Neue&quot;;\">This modern 4,362 square foot legacy home is a crown jewel of Martis Camp, offering privacy, provoking imaginations, and dishing up views from all its deck.<span class=\"Apple-converted-space\">&nbsp;</span><span style=\"font-family: &quot;Helvetica Neue&quot;;\">Immerse yourself in a luxury mountain experience like never before. Live amidst natural splendor, sunrise to sunset and twinkling stars,</span></p>',5,'property_features/1731665364_41438075_xl.jpg',6,'property_features/1731665364_Untitled-6.jpg',7,10,'9500-wawona-court','9500 Wawona Court','8,376,027','4,632',NULL,'Truckee','68',230,'96161',NULL,NULL,3,'property_features/1694447262_1%20copy%202.jpg','9500 Wawona Court','2024-11-22',310,0,NULL,NULL,2,'Royden Lepp LLC','Royden Lepp LLC','Video','2023-11-05 16:25:20',1,'2023-08-05 19:45:32','2025-07-03 11:32:09'),(2,9,'14828 MOUNTAIN WOOD DR','Nice Home','<p><span style=\"color: rgb(32, 33, 36); font-family: &quot;Google Sans&quot;, Roboto, arial, sans-serif; font-size: 20px;\">Squarespace offers straightforward payment and checkout options for your customers. Take online payments with&nbsp;</span><span style=\"background-color: rgba(80, 151, 255, 0.18); color: rgb(4, 12, 40); font-family: &quot;Google Sans&quot;, Roboto, arial, sans-serif; font-size: 20px;\">Stripe, Paypal, Apple Pay, and Afterpay</span><span style=\"color: rgb(32, 33, 36); font-family: &quot;Google Sans&quot;, Roboto, arial, sans-serif; font-size: 20px;\">&nbsp;(Afterpay is available in the US, Canada, Australia, and New Zealand).</span><br></p>',5,'property_features/1693272107_97777537_m.jpg',NULL,'property_features/1693272107_45169192_l.jpg',5,5,'14828-mountain-wood-dr','14828 MOUNTAIN WOOD DR','13,899,000','5,555',NULL,'WEED',NULL,230,'96094-9305',NULL,NULL,3,'property_features/1693272106_60870311_l%20%281%29.jpg','14828 MOUNTAIN WOOD DR','2024-04-14',4,0,NULL,NULL,0,NULL,NULL,NULL,'2023-11-27 01:25:33',1,'2023-08-29 01:19:55','2024-10-24 22:29:02'),(3,2,'23336 Lake Wenatchee Hwy','Immerse yourself in a luxury mountain experience unlike any other.','<p>Immerse yourself in a luxury mountain experience like never before. Live amidst natural splendor, sunrise to sunset and twinkling stars, Omnia Mountain Lodge lies within a category of legacy properties which rarely come available. A haven sprawled throughout 2.2 acres of private serenity, nestled between Leavenworth and Stevens Pass Ski Resort, Omnia Mountain Lodge was thoughtfully designed to embrace sweeping vistas. Serving as a modern retreat with classic Pacific Northwest elements, the lodge offers uncompromised indulgence. Over 7,000 square feet of space unfolds across ten bedrooms and six bathrooms, with opulent shared spaces and amenities. A truly rare opportunity!<br></p>',10,'property_features/1702056627_exteriormainfront.jpg',8,'property_features/1702056627_mainliving.jpg',6,10,'23336-lake-wenatchee-hwy-64','23336 Lake Wenatchee Hwy','13,450,000','7,006',NULL,'Leavenworth','68',230,'98826',NULL,NULL,3,'property_features/1702056626_lowergarage12.jpg','23336 Lake Wenatchee Hwy','2024-06-06',512,0,NULL,NULL,108,'Mark Parrott Films LLC','Clarity Northwest Photography - Tim Van Asselt','Video',NULL,1,'2023-12-08 16:00:39','2024-11-28 00:14:42'),(4,16,'14828 MOUNTAIN WOOD DR',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'14828-mountain-wood-dr-44','14828 MOUNTAIN WOOD DR',NULL,NULL,NULL,'WEED','8',230,'96094-9305',NULL,NULL,NULL,NULL,'14828 MOUNTAIN WOOD DR','2024-01-17',1,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,'2024-01-17 16:54:08','2024-04-13 14:56:22'),(5,23,'13709 107th Ave Ct E 7',NUL