NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,'2024-05-31 21:01:52','2024-05-31 21:01:52'),(22,38,'1234 Marbella Drive',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'1234-marbella-drive','1234 Marbella Drive',NULL,NULL,NULL,'Vacaville','8',230,'95688',NULL,NULL,NULL,NULL,'1234 Marbella Drive','2024-05-31',1,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,'2024-05-31 22:14:40','2024-05-31 23:40:20'),(23,2,'12018 109th St NW','Cape Cod Treasure','<p><span style=\"caret-color: rgb(10, 10, 10); color: rgb(10, 10, 10); font-family: Arial, Helvetica, sans-serif; font-size: 15.4px;\">Welcome to the pinnacle of Puget Sound living on Gig Harbor\'s Minter Cove the perfect combination of privacy, peacefulness, and proximity to the amenities of Gig Harbor. The masterfully built 2014 Cape Cod is prominently sited on 1.6 acres and 109 ft of shoreline offering stunning Mt. Rainier views, abundant shellfish, and world-class bird watching. The protected cove is ideal for kayaking and SUPs. The home features an expansive open concept design and a primary suite with 19 ft ceilings and spa-like bath. Entertain on the covered and heated waterfront porch or watch the game in the lower level bonus room. Feel your stress melt away as you enter the gated cobblestone driveway, breathe the salt air, and bask in the waterfront lifestyle.</span><br></p>',NULL,'',NULL,'',NULL,NULL,'12018-109th-st-nw','12018 109th St NW','3,995,000','5433',NULL,'Gig Harbor','68',230,'98329',NULL,NULL,NULL,'','12018 109th St NW','2025-02-08',23,1,NULL,NULL,0,'Reese Films','Clarity Photography','Video','2024-10-13 07:49:12',1,'2024-07-15 07:37:27','2025-08-12 06:19:05'),(24,36,'Dhammondi','Headline','<h5 class=\"mb-0\" style=\"--tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction