INSERT INTO `property_galleries` VALUES (1,1,'Exteriors','Over 4,000 square feet of space unfolds across five bedrooms and five and a half bathrooms, with opulent shared spaces and amenities. A truly rare opportunity!',1,'2023-08-05 19:49:22','2023-08-08 02:39:20'),(2,1,'Main Living Level','In the great room, tall Weiland pocket glass doors on opposing sides of the room disappear, ushering in to the great room, breakfast nook, kitchen and dining room.   There’s a soaring fireplace calling out from the corner of the great room.',1,'2023-08-05 22:26:47','2023-08-05 22:26:47'),(3,1,'Upper Level','Featured on the upper level is a theater room, recreation area and family room. with it\'s own deck and hot tub.',1,'2023-08-05 23:26:00','2023-08-06 00:03:40'),(4,1,'Lower Level','Great room w/ automated 39\' opening, indoor/outdoor living. Bowling alley, trackman golf simulator, 7-tv media room, game room.  3 laundry rooms. Pool, rooftop deck, 1000 sq ft exterior putting green, athletic court.',1,'2023-08-06 00:07:55','2023-09-13 17:52:39'),(5,1,'Dream Garage','A dream garage  is a 4,700 sq ft custom built (heated/insulated) toy shop. It comes complete with separate office, clean room and main work area and 3 PhantomPark 2-deck subterranean parking systems. The main shop area can hold 12+ cars and toys.',1,'2023-08-06 00:49:02','2023-08-07 15:07:45'),(6,2,'Dream Garage','Squarespace offers straightforward payment and checkout options for your customers. Take online payments with Stripe, Paypal, Apple Pay, and Afterpay (Afterpay is available in the US, Canada, Australia, and New Zealand).',1,'2023-08-29 01:24:10','2023-08-29 01:24:10'),(7,3,'Exteriors','Immerse yourself in a luxury mountain experience unlike any other. Nestled between Leavenworth and Stevens Pass Ski Resort, Omnia Mountain Lodge was thoughtfully designed to embrace sweeping vistas.',1,'2023-12-08 16:30:32','2023-12-10 16:44:35'),(8,3,'Main Level','Warm wood tones welcome you inside, where impressive vaulted ceilings with steel beams evoke a sense of decadence. A stone fireplace crackles, invigorating the senses while filling the residence with warmth, while chandeliers shine upon custom  finishes.',1,'2023-12-08 16:41:34','2023-12-10 16:44:41'),(9,3,'Upper Level','Upstairs a loft makes the prime location for a second living area with views Lake Wenatchee framed by treetops. The lodge is currently equipped to sleep up to 45 people throughout six chic bedrooms.',1,'2023-12-08 16:43:49','2023-12-10 16:44:50'),(10,3,'Lower Level','The seven accompanying bathrooms feature custom tilework, walk-in showers, free standing bathtubs, and backlit mirrors. World class amenities onsite beckon for memories to be made. Over 1,200 square feet of covered decks invite adventure during any season',1,'2023-12-08 16:47:31','2023-12-10 16:45:24'),(11,3,'Dream Garage','A dream garage  is a 4,700 sq ft custom built (heated/insulated) toy shop. It comes complete with separate office, clean room and main work area and 3 PhantomPark 2-deck subterranean parking systems. The main shop area can hold 12+ cars and toys!',1,'2023-12-08 16:48:01','2024-11-21 13:19:44'),(12,3,'Exteriors','Immerse yourself in a luxury mountain experience unlike any other. Nestled between Leavenworth and Stevens Pass Ski Resort, Omnia Mountain Lodge was thoughtfully designed to embrace sweeping vistas.',1,'2024-11-20 20:18:29','2024-11-20 20:18:29'),(15,26,'Exteriors','Nestled in the world renowned Martis Camp you will find a private ski access up to the Martis Camp Express Chairlift to Northstar California and a members-only ski lodge, a renowned 18-hole course designed by Tom Fazio, and exquisite dining.',1,'2024-11-21 14:50:56','2024-12-24 00:49:02'),(16,26,'Main Level','This 10 bedroom, 8 bathroom estate was designed by Shelton Construction.  Floors are eight-inch hickory while miter-edged countertops are Alpinus Granite. Appliances are Wolf, Sub-Zero and Viking.',1,'2024-12-24 00:51:08','2024-12-24 00:59:14'),(17,26,'Upper Level','The upper level is a  prime location for a second living area with views of Martis Valley framed by treetops.  Currently equipped to sleep up to 45 people throughout ten bedrooms.  Enjoy the home theater, wine room, and recreation area with bar.',1,'2024-12-24 01:07:23','2024-12-24 13:46:47'),(18,26,'Lower Level','The seven accompanying bathrooms feature custom tilework, walk-in showers, free standing bathtubs, and backlit mirrors. World class amenities onsite beckon for memories to be made. Over 1,200 square feet of covered decks invite adventure during any season',1,'2024-12-24 01:23:42','2024-12-24 13:47:15'),(19,26,'Dream Garage','A dream garage  is a 4,700 sq ft custom built (heated/insulated) toy shop. It comes complete with separate office, clean room and main work area and 3 PhantomPark 2-deck subterranean parking systems. The main shop area can hold 12+ cars and toys!',1,'2024-12-24 13:48:36','2024-12-24 13:48:36'),(25,23,'Gallery 1',NULL,1,'2025-06-09 17:27:05','2025-06-09 17:27:05');
/*!40000 ALTER TABLE `property_galleries` ENABLE KEYS */;
UNLOCK TABLES;

